PREFIX :     <https://sakuna.ph/>
PREFIX prov: <http://www.w3.org/ns/prov#>
SELECT ?eventName ?startDate
WHERE {
  # 1. Retrieve the event and its main details
  ?event a :DisasterEvent ;
         :eventName ?eventName .
  OPTIONAL { ?event :startDate ?startDate }

  # 2. Correlate: Check if this specific event has been attributed by more than one distinct source.
  {
    SELECT ?e WHERE {
      ?e prov:wasAttributedTo ?source . # Find all contributors for potential events
    } GROUP BY ?e HAVING (COUNT(DISTINCT ?source) > 1) # Filter down to events with multiple contributors
    FILTER (?e = ?event) # Link the count result back to the event in the outer scope
  }
}

