SELECT ?year (COUNT(?item) AS ?totalCount)
WHERE {
  {
    ?item a :MajorEvent ;
          :startDate ?startDate .
  }
  UNION
  {
    ?item a :Incident ;
          :hasRelatedIncident ?majorEvent . # Note: majorEvent variable is used but not strictly necessary for the count/date extraction
    ?item :startDate ?startDate .
  }

  BIND(YEAR(?startDate) AS ?year)
}
GROUP BY ?year
ORDER BY DESC(?totalCount)

