SELECT ?event 
       (?persons AS ?affectedPersons)
       (?families AS ?affectedFamilies)
       (GROUP_CONCAT(?barangay_loc; SEPARATOR=";") AS ?affectedBarangays)
       (?d_persons AS ?displacedPersons)
       (?d_families AS ?displacedFamilies)
       (GROUP_CONCAT(?center_loc; SEPARATOR=";") AS ?evacuationCenters)
WHERE {
  ?event a :DisasterEvent ;
         :hasAffectedPopulation ?ap .

  # --- Affected Data ---
  OPTIONAL { ?ap :affectedPersons ?persons . }
  OPTIONAL { ?ap :affectedFamilies ?families . }

  # --- Displaced Data ---
  OPTIONAL { ?ap :displacedPersons ?d_persons . }
  OPTIONAL { ?ap :displacedFamilies ?d_families . }

  # --- Location Data (These cause multiplication, necessitating GROUP_CONCAT) ---
  OPTIONAL { ?ap :hasLocation ?barangay_loc . }
  OPTIONAL { ?ap :hasEvacuationCenter ?center_loc . }

} GROUP BY ?event ?persons ?families ?d_persons ?d_families

