SELECT DISTINCT ?event ?generalDamageAmount ?generalDamageUnit ?insuredDamageAmount ?insuredDamageUnit ?cpiValue
WHERE {
  ?event a :DisasterEvent .

  # Link the event to its damage report (InfrastructureDamage)
  OPTIONAL {
    ?event :hasInfrastructureDamage ?damageReport .

    # General Damage Information (Mapped to Infrastructure/General Loss)
    OPTIONAL { ?damageReport :infraDamageAmount ?generalDamageAmount . }
    # The unit might apply to the specific damage amount (e.g., General Loss)
    OPTIONAL { ?damageReport :hasDamageUnit ?generalDamageUnit . } 

    # Insured Damage Information (Mapped to Commercial Loss)
    OPTIONAL { ?damageReport :commercialDamageAmount ?insuredDamageAmount . }
    # Assuming the insured damage uses the same dimensional unit property of the report
    OPTIONAL { ?damageReport :hasDamageUnit ?insuredDamageUnit . } 

    # CPI Value (a property of the report)
    OPTIONAL { ?damageReport :hasCpiValue ?cpiValue . }
  }
}

