SELECT DISTINCT ?event ?eventName ?damageTypeLabel ?damageStatusLabel ?startDate ?endDate
WHERE {
  # 1. Identify the disaster event and its infrastructure damage report
  ?event a :DisasterEvent ;
         :hasInfrastructureDamage ?inf .

  # 2. Filter the specific damage reports to those concerning roads or bridges
  ?inf :assetType ?assetURI .
  FILTER (?assetURI IN ("RoadSegment", "BridgeCrossing"))

  # 3. Retrieve the damage classification and status information
  ?inf :damageClassification ?typeURI .
  ?inf :damageStatus ?statusURI .

  # 4. Retrieve event metadata (optional)
  OPTIONAL { ?event :eventName ?eventName }
  OPTIONAL { ?event :startDate ?startDate }
  OPTIONAL { ?event :endDate ?endDate }

  # 5. Resolve URIs/IDs to human-readable labels for output
  OPTIONAL { ?typeURI rdfs:label ?damageTypeLabel . }
  OPTIONAL { ?statusURI rdfs:label ?damageStatusLabel . }

} LIMIT 100

SELECT ?eventName ?airportType ?airlineName ?flightNumber ?routeDetails ?cancellationTime ?resumptionTime
WHERE {
  ?disruption a :DisasterEvent ;
    :hasEventType "AirportDisruption" ;
    :startDate ?startDate .

  # 1. Define the event name and type/location
  OPTIONAL { ?disruption :eventName ?eventName . }
  ?disruption :hasRoute ?routeDetails .

  # 2. Link to the physical locations (Airport) and properties
  ?disruption :hasAffectedAirport ?airport ;
    :properties ?airportType .

  # 3. Link to the Flight/Incident specifics (Optional)
  OPTIONAL { 
    ?disruption :isFlightIncident ?flight .

    # Flight details
    OPTIONAL { ?flight :hasFlightNumber ?flightNumber . }
    OPTIONAL { 
      ?flight :hasAirline ?airline .
      BIND(?airline AS ?airlineName) # Mapping airline object to bound variable
    }
  }

  # 4. Temporal details of the disruption (optional)
  OPTIONAL { ?disruption :hasCancellationTime ?cancellationTime . }
  OPTIONAL { ?disruption :hasResumptionTime ?resumptionTime . }

}
ORDER BY DESC(?startDate)

SELECT ?event ?eventName ?providerLabel ?substationLabel ?interruptionStart ?restorationEnd
WHERE {
  ?event a :DisasterEvent ;
         :hasInfrastructureDamage ?damageReport .

  # Identify the specific type of damage (Power Disruption)
  ?damageReport :isType "PowerDisruption" .

  # Link the damage report to specific infrastructure components
  ?damageReport :affectedService ?provider ;
                :causedBySubstation ?substation .

  # Retrieve readable names/labels for the involved entities
  ?provider rdfs:label ?providerLabel .
  ?substation rdfs:label ?substationLabel .

  # Retrieve event details (using optional matches for non-critical fields)
  OPTIONAL { ?event :eventName ?eventName }

  # Retrieve service interruption timing details linked to the Event
  ?event :serviceInterruptionStartDate ?interruptionStart .

  # Retrieve restoration time if available
  OPTIONAL { ?event :serviceRestorationEndDate ?restorationEnd . }
}

SELECT ?eventName ?telecomCompany ?communicationStatus
WHERE {
  ?event a :DisasterEvent ;
         :hasInfrastructureDamage ?damageReport .

  # Filter for damage specifically related to communication failure/disruption
  ?damageReport :affectedService ?service . 
  FILTER (?service = :TelecommunicationsNetwork) # Filter based on the specific service URI

  # Link the damage to the specific company and status
  ?damageReport :involvingEntity ?telecomCompany ;
                 :impactStatus ?communicationStatus .

  # Retrieve event details for display
  OPTIONAL { ?event :eventName ?eventName }
}

