SELECT DISTINCT ?entityLabel ?dtype
WHERE {
  # Step 1: Find the potential entities linked to any disaster event
  { ?event a :DisasterEvent ;
         :hasAssistance ?entity . }
  UNION
  { ?event a :DisasterEvent ;
         :hasInfrastructureDamage ?entity . }
  UNION
  { ?event a :DisasterEvent ;
         :hasAffectedPopulation ?entity . }

  # Step 2: Find the description property on that entity
  ?entity rdfs:comment ?description . 

  # Step 3: Filter based on required recovery keywords
  FILTER regex(?description, "recovery|training|policy change|post-structure cost", "i")

  # Step 4: Gather optional context about the disaster type
  OPTIONAL { ?event :hasDisasterType ?dtype }

  # Step 5: Bind the unique identifier of the entity for output
  BIND(STR(?entity) AS ?entityLabel) 
}
ORDER BY DESC(?dtype)

SELECT ?event ?sourceResourceLabel ?organizationLabel
WHERE {
  ?event a :DisasterEvent .

  # Traverse the complete derivation chain (Provenance)
  ?event prov:wasDerivedFrom+ ?derivedResource .

  # Find the organization that contributed/attributed this information
  OPTIONAL { ?event prov:wasAttributedTo ?organization . }

  # Optional: Add labels for human readability of the resources
  OPTIONAL { ?derivedResource rdfs:label ?sourceResourceLabel . }
  OPTIONAL { ?organization rdfs:label ?organizationLabel . }

} LIMIT 100

