SELECT ?dtypeLabel ?dtypeDefinition ?broaderParent WHERE {
  ?dtype a :DisasterType .
  OPTIONAL { ?dtype skos:prefLabel ?dtypeLabel . }
  OPTIONAL { ?dtype rdfs:label ?dtypeDefinition . }
  OPTIONAL { ?dtype skos:broader ?broaderParent . }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-roflinements#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>

SELECT DISTINCT ?objectPropertyLabel (STR(?domainLabel) AS ?DomainClass),
             (STR(?rangeLabel) AS ?RangeClass),
             ?inversePropertyLabel,
             ?superPropertyLabel
WHERE {
  # Identify the base object property
  ?objectProperty a owl:ObjectProperty .

  # Metadata discovery - Domain
  OPTIONAL {
    ?objectProperty rdfs:domain ?domain .
    OPTIONAL { ?domain rdfs:label ?domainLabel }
  }

  # Metadata discovery - Range
  OPTIONAL {
    ?objectProperty rdfs:range ?range .
    OPTIONAL { ?range rdfs:label ?rangeLabel }
  }

  # Metadata discovery - Inverse Property
  OPTIONAL {
    ?objectProperty owl:inverseOf ?inverseProperty .
    OPTIONAL { ?inverseProperty rdfs:label ?inversePropertyLabel }
  }

  # Metadata discovery - Super Property (transitive parent relationship)
  OPTIONAL {
    ?objectProperty rdfs:subPropertyOf* ?superProperty .
    OPTIONAL { ?superProperty rdfs:label ?superPropertyLabel }
  }

  # Retrieve object property label
  OPTIONAL { ?objectProperty rdfs:label ?objectPropertyLabel . }

}

SELECT ?propertyLabel (STR(?domain_uri) AS ?DomainURI) (STR(?range_uri) AS ?RangeURI)
WHERE {
  ?prop a owl:DatatypeProperty ;
        rdfs:label ?propertyLabel .
  OPTIONAL { ?prop rdfs:domain ?domain_uri . }
  OPTIONAL { ?prop rdfs:range ?range_uri . }
}

SELECT DISTINCT ?casualtyTypeLabel WHERE {
  ?c a :Casualties ;
     :isOfCasualtyType ?casualtyTypeLabel .
}

SELECT ?currencyUnitLabel WHERE {
  {
    # Query for Philippine Peso Millions unit definition
    ?unit a cur:Unit ;
          rdfs:label ?currencyUnitLabel .
    FILTER (CONTAINS(?unit, "Philippine Peso"))
    # Attempt to match scaling context for millions (10^6)
    OPTIONAL { ?unit :scaleFactor "1000000"^^xsd:integer }
  }
  UNION
  {
    # Query for US Dollar Thousands unit definition
    ?unit a cur:Unit ;
          rdfs:label ?currencyUnitLabel .
    FILTER (CONTAINS(?unit, "US Dollar"))
    # Attempt to match scaling context for thousands (10^3)
    OPTIONAL { ?unit :scaleFactor "1000"^^xsd:integer }
  }
}

SELECT ?event ?startDate ?endDate
WHERE {
  ?event a :DisasterEvent ;
         :startDate ?startDate ;
         :endDate ?endDate .
  FILTER (?endDate < ?startDate)
}

SELECT ?casualtyResource
WHERE {
    # Identify potential impact resources (Casualties)
    ?casualtyResource a :Casualties .

    # Ensure this resource is NOT linked to any Disaster Event
    FILTER NOT EXISTS {
        ?event a :DisasterEvent ;
              :hasCasualties ?casualtyResource .
    }
}

SELECT ?event WHERE {
  ?event a :MajorEvent .
  # Find MajorEvents that have related incidents.
  :hasRelatedIncident ?incident .
} LIMIT 1

SELECT DISTINCT ?assistanceResource ?numericValue WHERE {
  ?assistanceResource a :Assistance ;
    qudt:numericValue ?numericValue .

  # Ensure there is no QUDT unit defined for this assistance resource
  FILTER NOT EXISTS {
    ?assistanceResource qudt:unit ?unit .
  }
}

SELECT ?event ?eventName ?startDate
WHERE {
  ?event a :DisasterEvent ;
         :startDate ?startDate .
  OPTIONAL { ?event :eventName ?eventName }
  FILTER (?startDate >= "2099-01-01T00:00:00"^^xsd:dateTime && ?startDate < "2100-01-01T00:00:00"^^xsd:dateTime)
}
ORDER BY ?startDate

SELECT ?event ?eventName ?startDate
