SELECT (COUNT(?event) AS ?EventCount)
WHERE {
  ?event a :DisasterEvent ;
         :hasLocation ?location .
  FILTER (?location rdfs:label = "National Capital Region")
}

SELECT (SUM(?count) AS ?TotalFatalities)
WHERE {
  ?event a :DisasterEvent ;
         :hasDisasterType ?earthquakeType . 
  ?event :hasCasualties ?casualtyRecord .
  FILTER (?earthquakeType = :Earthquake) # Assuming a specific resource binds to the Earthquake type
  ?casualtyRecord :isOfCasualtyType "dead" ;
                   :casualtyCount ?count .
}

